from flask import Flask, send_from_directory
app = Flask(__name__)
app.config['SEND_FILE_MAX_AGE_DEFAULT'] = 0
app.config['STATIC_URL_BASE'] = '/static/'
app.config['UPLOAD_FOLDER'] = 'uploads'
app.config['STATIC_FOLDER'] = app.config['UPLOAD_FOLDER']

def legacy_filename(filename):
    # This is a simple example of handling legacy filenames.
    # In a real-world scenario, you might need more complex logic.
    if '.' not in filename:
        return f"{filename}.static"
    return filename

@app.route('/<path:file_name>')
def send_legacy_static(file_name):
    file_path = f"{app.config['STATIC_FOLDER']}/{legacy_filename(file_name)}"
    try:
        return send_from_directory(directory=file_path, filename=file_name)
    except FileNotFoundError:
        return send_from_directory(directory=app.config['STATIC_FOLDER'], filename='404.html')

